import{_ as i,o as t,c as r,ag as a}from"./chunks/framework.CvgP6Fyv.js";const g=JSON.parse('{"title":"Recurring Invoices","description":"","frontmatter":{},"headers":[],"relativePath":"features/recurring-invoices.md","filePath":"features/recurring-invoices.md"}'),n={name:"features/recurring-invoices.md"};function o(l,e,s,c,u,d){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="recurring-invoices" tabindex="-1">Recurring Invoices <a class="header-anchor" href="#recurring-invoices" aria-label="Permalink to &quot;Recurring Invoices&quot;">​</a></h1><p>Automate your regular billing by setting up invoices that generate on a schedule.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Recurring invoices are templates that automatically create new invoices at specified intervals. Ideal for:</p><ul><li>Monthly retainers</li><li>Subscription billing</li><li>Rent collection</li><li>Maintenance contracts</li><li>Regular consulting fees</li></ul><h2 id="creating-a-recurring-invoice" tabindex="-1">Creating a recurring invoice <a class="header-anchor" href="#creating-a-recurring-invoice" aria-label="Permalink to &quot;Creating a recurring invoice&quot;">​</a></h2><ol><li>Go to <strong>Recurring Invoices &gt; New</strong></li><li>Fill in the template: <ul><li><strong>Customer</strong> — Who to bill</li><li><strong>Line items</strong> — What to bill for (descriptions, amounts, VAT)</li><li><strong>Frequency</strong> — How often (weekly, monthly, quarterly, yearly)</li><li><strong>Start date</strong> — When to start generating</li></ul></li><li>Click <strong>Save</strong></li></ol><p>The recurring invoice is created in <strong>Active</strong> status and will generate its first invoice on the next scheduled date.</p><h2 id="frequency-options" tabindex="-1">Frequency options <a class="header-anchor" href="#frequency-options" aria-label="Permalink to &quot;Frequency options&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Frequency</th><th>Description</th></tr></thead><tbody><tr><td><strong>Weekly</strong></td><td>Every 7 days</td></tr><tr><td><strong>Monthly</strong></td><td>Same day each month</td></tr><tr><td><strong>Quarterly</strong></td><td>Every 3 months</td></tr><tr><td><strong>Yearly</strong></td><td>Once per year</td></tr></tbody></table><h2 id="managing-recurring-invoices" tabindex="-1">Managing recurring invoices <a class="header-anchor" href="#managing-recurring-invoices" aria-label="Permalink to &quot;Managing recurring invoices&quot;">​</a></h2><h3 id="pause" tabindex="-1">Pause <a class="header-anchor" href="#pause" aria-label="Permalink to &quot;Pause&quot;">​</a></h3><p>Temporarily stop invoice generation:</p><ol><li>Open the recurring invoice</li><li>Click <strong>Pause</strong></li><li>Status changes to <strong>Paused</strong> — no invoices are generated</li></ol><h3 id="resume" tabindex="-1">Resume <a class="header-anchor" href="#resume" aria-label="Permalink to &quot;Resume&quot;">​</a></h3><p>Restart a paused recurring invoice:</p><ol><li>Open the paused recurring invoice</li><li>Click <strong>Resume</strong></li><li>Generation continues from the next scheduled date</li></ol><h3 id="edit" tabindex="-1">Edit <a class="header-anchor" href="#edit" aria-label="Permalink to &quot;Edit&quot;">​</a></h3><p>Editing a recurring invoice affects <strong>future</strong> invoices only. Previously generated invoices are not changed.</p><h3 id="delete" tabindex="-1">Delete <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;Delete&quot;">​</a></h3><p>Remove the recurring template entirely. Previously generated invoices remain in your records.</p><h2 id="generated-invoices" tabindex="-1">Generated invoices <a class="header-anchor" href="#generated-invoices" aria-label="Permalink to &quot;Generated invoices&quot;">​</a></h2><p>Each time a recurring invoice fires, a new invoice is created:</p><ul><li>It uses the template&#39;s line items and customer</li><li>It follows your current invoice numbering</li><li>It starts as a <strong>Draft</strong> (review and send) or auto-sends if configured</li><li>Each generated invoice is independent — you can edit it without affecting the template</li></ul><h2 id="viewing-history" tabindex="-1">Viewing history <a class="header-anchor" href="#viewing-history" aria-label="Permalink to &quot;Viewing history&quot;">​</a></h2><p>The recurring invoice detail page shows all previously generated invoices, so you can track the full billing history.</p><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><ul><li><strong>Pause / Resume</strong> — Toggle multiple recurring invoices</li><li><strong>Delete</strong> — Remove multiple templates</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Combine with <a href="/features/contracts">contracts</a> for contract-based billing</li><li>Review generated invoices before the first auto-send to make sure everything looks right</li><li>Use the next occurrence preview to see when the next invoice will be created</li><li>Check the active count and metrics at the top of the page</li></ul>',30)])])}const v=i(n,[["render",o]]);export{g as __pageData,v as default};
